+			peer: config.Peer{
+				Endpoints:     mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820"),
+				EndpointSpecs: []config.EndpointSpec{lit("203.0.113.1:51820"), lit("198.51.100.7:51820")},
+			},
