+		nameSpec("shadow.example.com", 51820), // spec 0: hostname, EMPTY at boot
+		litSpec(t, "203.0.113.1:51820"),       // spec 1: literal dup → boot-active (flat[0])
+		litSpec(t, "198.51.100.7:51820"),      // spec 2: literal standby
+	}
